package day39;

// Step 1: Run this WITHOUT Spring to understand what Spring does behind the scenes.
// We will manually call each lifecycle step so you can see the order clearly.
// In a real Spring app, Spring calls all of this automatically.

public class LifecycleDemo {

    // This is our "bean" — just a plain Java class
    static class WelcomeService {

        private String greeting; // will be "injected" (set) from outside

        // Step 1: Constructor — called by Spring first
        // At this point, greeting is still null
        public WelcomeService() {
            System.out.println("1. Constructor called. greeting = " + greeting); // null!
        }

        // Step 2: Injection — Spring sets this field after construction
        public void setGreeting(String greeting) {
            this.greeting = greeting;
            System.out.println("2. Injection done. greeting = " + greeting);
        }

        // Step 3: @PostConstruct equivalent — Spring calls this after injection
        // Now greeting is available. Safe to use it.
        public void init() {
            System.out.println("3. PostConstruct: ready to serve. greeting = " + greeting);
        }

        // Step 4: Normal usage
        public void welcome(String name) {
            System.out.println("4. Business logic: " + greeting + ", " + name + "!");
        }

        // Step 5: @PreDestroy equivalent — Spring calls this on shutdown
        public void cleanup() {
            System.out.println("5. PreDestroy: shutting down, releasing resources.");
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Spring does all of this automatically. We do it manually so you can see it. ===\n");

        // Spring internally does exactly these steps:

        // Step 1: construct
        WelcomeService service = new WelcomeService();

        // Step 2: inject
        service.setGreeting("Hello");

        // Step 3: PostConstruct
        service.init();

        System.out.println("\n--- App is running ---\n");

        // Step 4: use the bean normally
        service.welcome("Satyam");
        service.welcome("Priya");

        System.out.println("\n--- App is shutting down ---\n");

        // Step 5: PreDestroy
        service.cleanup();
    }
}

package day39;

// Now the same concepts but with real Spring annotations.
// This is a Spring Boot app — Spring calls everything automatically.

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.stereotype.Component;
import org.springframework.context.annotation.Primary;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.beans.factory.ObjectFactory;
import org.springframework.context.annotation.Scope;
import jakarta.annotation.PostConstruct;
import jakarta.annotation.PreDestroy;
import java.util.List;

// ─────────────────────────────────────────────────────────────────────────
// EXAMPLE 1: @PostConstruct and @PreDestroy in action
// Scenario: A service that loads product data into memory on startup
// ─────────────────────────────────────────────────────────────────────────

@Service
public class ProductCacheService {

    @Autowired
    private ProductRepository repository; // Spring injects this first

    private List<String> cache;

    // Spring calls this automatically after repository is injected
    @PostConstruct
    public void loadCache() {
        // Safe to use repository here — it is already injected
        cache = repository.findAllProductNames();
        System.out.println("Cache loaded with " + cache.size() + " products at startup.");
    }

    public List<String> getProducts() {
        return cache; // instant, no database call needed
    }

    // Spring calls this when the application shuts down
    @PreDestroy
    public void clearCache() {
        cache.clear();
        System.out.println("Cache cleared on shutdown.");
    }
}

// ─────────────────────────────────────────────────────────────────────────
// EXAMPLE 2: @Primary and @Qualifier
// Scenario: Two notification services — email (default) and SMS (on demand)
// ─────────────────────────────────────────────────────────────────────────

interface NotificationService {
    void send(String message);
}

@Service
@Primary // Spring picks this one by default when no @Qualifier is specified
class EmailNotificationService implements NotificationService {
    @Override
    public void send(String message) {
        System.out.println("EMAIL: " + message);
    }
}

@Service("smsNotification") // we give it a specific name for @Qualifier
class SmsNotificationService implements NotificationService {
    @Override
    public void send(String message) {
        System.out.println("SMS: " + message);
    }
}

@Service
public class OrderService {

    // Gets EmailNotificationService because it is @Primary
    @Autowired
    private NotificationService defaultNotifier;

    // Gets SmsNotificationService because we specified the qualifier name
    @Autowired
    @Qualifier("smsNotification")
    private NotificationService smsNotifier;

    public void placeOrder(String item, String method) {
        System.out.println("Order placed: " + item);
        if ("sms".equals(method)) {
            smsNotifier.send("Your order for " + item + " is confirmed!");
        } else {
            defaultNotifier.send("Your order for " + item + " is confirmed!");
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────
// EXAMPLE 3: Scope mismatch — the most common beginner bug
// Scenario: A Cart bean that should be unique per user,
//           but gets stuck as one shared cart because of scope mismatch.
// ─────────────────────────────────────────────────────────────────────────

@Component
@Scope("prototype") // new instance every time getObject() is called
class Cart {
    private final java.util.List<String> items = new java.util.ArrayList<>();

    public void addItem(String item) { items.add(item); }
    public List<String> getItems() { return items; }
}

// BAD: injecting Cart directly into a singleton
@Service
class CheckoutServiceBuggy {

    // Problem: Spring injects ONE Cart at startup and reuses it forever.
    // User A and User B share the same Cart — their items mix. Bug!
    @Autowired
    private Cart cart;

    public void addToCart(String item) { cart.addItem(item); }
    public List<String> getCart() { return cart.getItems(); }
}

// GOOD: inject ObjectFactory so we get a fresh Cart per call
@Service
class CheckoutServiceFixed {

    // ObjectFactory creates a new Cart every time getObject() is called
    @Autowired
    private ObjectFactory<Cart> cartFactory;

    public Cart getCartForCurrentUser() {
        return cartFactory.getObject(); // fresh Cart every time
    }
}

// ─────────────────────────────────────────────────────────────────────────
// EXAMPLE 4: @Value — reading from application.properties
// application.properties: app.max-retries=3, app.service-name=OrderAPI
// ─────────────────────────────────────────────────────────────────────────

@Service
class RetryService {

    @Value("${app.max-retries:3}") // reads from properties, default 3
    private int maxRetries;

    @Value("${app.service-name:DefaultService}")
    private String serviceName;

    @PostConstruct
    public void logConfig() {
        // Both values are injected before this runs
        System.out.println(serviceName + " will retry up to " + maxRetries + " times.");
    }

    public void callWithRetry(Runnable action) {
        for (int i = 1; i <= maxRetries; i++) {
            try { action.run(); return; }
            catch (Exception e) {
                System.out.println("Attempt " + i + " failed. " +
                    (i < maxRetries ? "Retrying..." : "Giving up."));
            }
        }
    }
}

package day39;

// Advanced patterns: BeanPostProcessor, circular dependency fix,
// @DependsOn, and @Lazy. These are real production scenarios.

import org.springframework.beans.factory.config.BeanPostProcessor;
import org.springframework.context.annotation.DependsOn;
import org.springframework.context.annotation.Lazy;
import org.springframework.stereotype.Component;
import org.springframework.stereotype.Service;
import org.springframework.beans.factory.annotation.Autowired;
import jakarta.annotation.PostConstruct;

// ─────────────────────────────────────────────────────────────────────────
// ADVANCED 1: BeanPostProcessor — running code around every bean
//
// Imagine you want to log the startup time of every single bean.
// You cannot add @PostConstruct to 100 classes manually.
// BeanPostProcessor lets you intercept every bean creation in one place.
// ─────────────────────────────────────────────────────────────────────────

@Component
public class StartupTimerBPP implements BeanPostProcessor {

    // Called BEFORE each bean's @PostConstruct (and other init callbacks)
    @Override
    public Object postProcessBeforeInitialization(Object bean, String beanName) {
        // We just store the start time. We use the beanName as a key.
        StartupTimerRegistry.start(beanName);
        return bean; // IMPORTANT: always return the bean (or a replacement)
    }

    // Called AFTER each bean's @PostConstruct (and other init callbacks)
    @Override
    public Object postProcessAfterInitialization(Object bean, String beanName) {
        long ms = StartupTimerRegistry.stop(beanName);
        if (ms > 200) {
            System.out.println("SLOW BEAN: " + beanName + " took " + ms + "ms to initialize!");
        }
        // Returning bean as-is. Spring's AOP infrastructure returns a PROXY here instead,
        // which is how @Transactional, @Async etc work under the hood.
        return bean;
    }
}

// Simple registry to track timing (not thread-safe — demo only)
class StartupTimerRegistry {
    private static final java.util.Map<String, Long> times = new java.util.HashMap<>();
    static void start(String name) { times.put(name, System.currentTimeMillis()); }
    static long stop(String name) {
        Long start = times.remove(name);
        return start == null ? 0 : System.currentTimeMillis() - start;
    }
}

// ─────────────────────────────────────────────────────────────────────────
// ADVANCED 2: @DependsOn — controlling startup order without injection
//
// Real scenario: You have a DatabaseMigrationService that creates tables.
// The UserRepository must only start AFTER migrations are done.
// But UserRepository does not @Autowire the migration service.
// @DependsOn solves this — it is ordering without injection.
// ─────────────────────────────────────────────────────────────────────────

@Service("databaseMigration")
public class DatabaseMigrationService {

    @PostConstruct
    public void runMigrations() {
        System.out.println("DatabaseMigration: creating/updating tables...");
        // In real code: Flyway or Liquibase runs here
        System.out.println("DatabaseMigration: schema is ready.");
    }
}

@Service
@DependsOn("databaseMigration") // wait for migration before starting
public class UserRepository {

    @PostConstruct
    public void init() {
        // By the time this runs, databaseMigration has already completed
        System.out.println("UserRepository: connecting (tables are guaranteed to exist).");
    }

    public String findByEmail(String email) {
        return "User[" + email + "]"; // simplified
    }
}

// ─────────────────────────────────────────────────────────────────────────
// ADVANCED 3: Circular dependency and how to fix it properly
//
// BAD design: InvoiceService needs PaymentService, PaymentService needs InvoiceService.
// Spring cannot create either. Fails at startup.
//
// WRONG fix: @Lazy on one of them (hides the problem, doesn't fix it).
// RIGHT fix: extract shared logic into a third class both can depend on.
// ─────────────────────────────────────────────────────────────────────────

// THE PROBLEM (do not do this):
/*
@Service class InvoiceService {
    @Autowired PaymentService paymentService; // needs PaymentService
}
@Service class PaymentService {
    @Autowired InvoiceService invoiceService; // needs InvoiceService — CIRCULAR!
}
// Spring throws: "The dependencies of some of the beans in the application
//                context form a cycle: invoiceService -> paymentService -> invoiceService"
*/

// THE FIX: extract the shared behaviour into EventBus
// Neither class needs the other. Both depend only on EventBus.

@Service
class EventBus {
    public void publish(String event, Object data) {
        System.out.println("EVENT [" + event + "]: " + data);
        // In real apps: listeners subscribe and react to events
    }
}

@Service
class InvoiceService {
    @Autowired private EventBus eventBus; // depends on EventBus, not PaymentService

    public void createInvoice(String orderId) {
        System.out.println("Invoice created for order: " + orderId);
        eventBus.publish("invoice.created", orderId); // fire event instead of direct call
    }
}

@Service
class PaymentService {
    @Autowired private EventBus eventBus; // depends on EventBus, not InvoiceService

    public void processPayment(String orderId, double amount) {
        System.out.println("Payment of $" + amount + " processed for order: " + orderId);
        eventBus.publish("payment.processed", orderId);
    }
}

// ─────────────────────────────────────────────────────────────────────────
// ADVANCED 4: How @Transactional actually works (the proxy secret)
//
// When you put @Transactional on a method, Spring wraps your class in a proxy.
// Callers talk to the proxy, not your real class.
// The proxy starts a transaction, calls your method, then commits or rolls back.
//
// The famous self-invocation bug: calling a @Transactional method from within
// the same class bypasses the proxy — the transaction never starts.
// ─────────────────────────────────────────────────────────────────────────

@Service
class TransactionDemo {

    // This works: external caller -> proxy -> this method -> transaction starts
    @org.springframework.transaction.annotation.Transactional
    public void saveOrder(String orderId) {
        System.out.println("Saving order " + orderId + " inside a transaction.");
        // If exception thrown here, transaction rolls back automatically
    }

    // This DOES NOT work as expected:
    public void processBatch(java.util.List<String> orderIds) {
        for (String id : orderIds) {
            // Calling saveOrder from within the same class bypasses the proxy!
            // No transaction is started. @Transactional is silently ignored.
            saveOrder(id); // BAD: direct call, not through proxy
        }
    }

    // Fix: move processBatch to a DIFFERENT class, or inject self (ugly but works)
}

