        persistenceService.saveOrder(item); // goes through proxy — transaction works
    }
}

// Problem: this prototype opens a connection, but @PreDestroy never fires
@Component @Scope("prototype")
public class ReportExporter {
    private Connection conn;

    @PostConstruct
    public void open() {
        conn = dataSource.getConnection(); // opens connection
    }

    @PreDestroy
    public void close() {
        conn.close(); // NEVER CALLED for prototype beans!
    }
}

// FIX A — implement AutoCloseable and use try-with-resources
@Component @Scope("prototype")
public class ReportExporter implements AutoCloseable {
    private Connection conn;

    @PostConstruct
    public void open() { conn = dataSource.getConnection(); }

    @Override
    public void close() { conn.close(); } // caller controls cleanup
}

// Caller:
try (ReportExporter exporter = exporterFactory.getObject()) {
    exporter.generate(reportId);
} // close() called automatically here

