// BUG — MockEmailService has @Primary without @Profile("test")
@Service
@Primary // THIS IS THE BUG — no profile restriction
public class MockEmailService implements EmailService {
    @Override
    public void send(String to, String body) {
        System.out.println("[MOCK] Email to " + to); // silently swallows all emails
    }
