// FIX — restrict stub to test profile only
@Service
@Profile("test") // only registered when Spring profile "test" is active
public class MockEmailService implements EmailService {
    @Override
    public void send(String to, String body) {
        System.out.println("[TEST MOCK] Email to " + to);
