// BUG — slow @PostConstruct blocks the entire startup thread
@Service
public class ReferenceDataLoader {
    @Autowired private CountryRepository countryRepo;

    @PostConstruct
    public void load() throws Exception {
        // This takes 25 seconds — health check port is unreachable during this time
        Thread.sleep(25_000); // simulating slow external data load
        System.out.println("Reference data loaded.");
    }
}

// FIX — start slow work on a background thread, expose readiness indicator
@Service
public class ReferenceDataLoader {
    @Autowired private CountryRepository countryRepo;
    private volatile boolean ready = false;

    @PostConstruct
    public void scheduleLoad() {
        // Return immediately — health check can now respond
        new Thread(() -> {
            // slow work happens in background
            try { Thread.sleep(25_000); } catch (InterruptedException e) { return; }
            ready = true;
            System.out.println("Reference data loaded.");
        }).start();
    }

    public boolean isReady() { return ready; }
    // Wire this into a Spring Boot ReadinessIndicator
}

// Project structure:
// com.myapp.Main.java  (@SpringBootApplication)
// com.myapp.service.OrderService.java  — FOUND (sub-package)
// com.utils.EmailHelper.java  — NOT FOUND (different package tree!)

// WRONG — EmailHelper is outside com.myapp
package com.utils;
@Service // Spring never sees this — wrong package
public class EmailHelper { ... }

// FIX A — move to a sub-package of Main
package com.myapp.util;
@Service // Spring finds this — sub-package of com.myapp
public class EmailHelper { ... }

// FIX B — add the package to @ComponentScan explicitly
@SpringBootApplication
@ComponentScan(basePackages = {"com.myapp", "com.utils"})
