            if (!pool.awaitTermination(10, TimeUnit.SECONDS)) {
                System.out.println("OrderProcessingPool: timeout — force stopping.");
                pool.shutdownNow(); // interrupt running tasks
            } else {
                System.out.println("OrderProcessingPool: all orders completed cleanly.");
