@Component
public class StartupTimerBPP implements BeanPostProcessor {

    private final ConcurrentHashMap<String, Long> times = new ConcurrentHashMap<>();

    @Override
    public Object postProcessBeforeInitialization(Object bean, String name) {
        times.put(name, System.currentTimeMillis());
        return bean; // must return the bean
    }

    @Override
    public Object postProcessAfterInitialization(Object bean, String name) {
        Long start = times.remove(name);
        if (start != null) {
            long ms = System.currentTimeMillis() - start;
            String label = ms > 500 ? "SLOW! " : ms > 100 ? "WARN  " : "OK    ";
            System.out.printf("[BPP] %s %-40s %dms%n", label, name, ms);
        }
        return bean; // must return the bean
    }
}

